import { Component, OnInit } from '@angular/core';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { CommonModule } from '@angular/common';
import { Account, Role } from '@app/_models';
import { AccountService } from '@app/_services';
import { AlertComponent } from '@app/_components/alert.component';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive, AlertComponent]
})
export class AppComponent implements OnInit {
  Role = Role;
  account: Account | null = null;

  constructor(private accountService: AccountService) { }

  ngOnInit() {
    this.accountService.account.subscribe(x => this.account = x);
  }

  get isAdmin() {
    return this.account?.role === Role.Admin;
  }

  logout() {
    this.accountService.logout();
  }
}
<nav class="navbar navbar-expand navbar-dark bg-dark" *ngIf="account">
  <div class="container">
    <a class="navbar-brand" routerLink="/">Angular Auth Boilerplate</a>
    <ul class="navbar-nav">
      <li class="nav-item">
        <a class="nav-link" routerLink="/" routerLinkActive="active" [routerLinkActiveOptions]="{exact: true}">Home</a>
      </li>
      <li class="nav-item">
        <a class="nav-link" routerLink="/profile" routerLinkActive="active">Profile</a>
      </li>
      <li class="nav-item" *ngIf="isAdmin">
        <a class="nav-link" routerLink="/admin" routerLinkActive="active">Admin</a>
      </li>
      <li class="nav-item">
        <a class="nav-link" (click)="logout()">Logout</a>
      </li>
    </ul>
  </div>
</nav>

<router-outlet name="subnav"></router-outlet>

<div class="container pt-4">
  <alert></alert>
  <router-outlet></router-outlet>
</div>
